184	function detectRepetition(recent: string[]): boolean {
185	  if (recent.length < REPETITION_THRESHOLD) return false;
186	  const last = recent[recent.length - 1];
187	  let count = 0;
188	  for (let i = recent.length - 1; i >= 0 && i >= recent.length - 5; i--) {
189	    if (recent[i] === last) count++;
190	  }
191	  return count >= REPETITION_THRESHOLD;
192	}
